//! Dataset loading and batching for ability operator training.
//!
//! Loads npz files generated by `xtask scenario oracle operator-dataset`
//! into GPU tensors for fast batch sampling.

use burn::prelude::*;
use ndarray::Array2;
use ndarray_npy::NpzReader;
use std::path::Path;

use crate::loss::LossMask;
use crate::model::*;

/// Full training dataset loaded into GPU memory.
pub struct OperatorDataset<B: Backend> {
    // Encoder inputs (state before ability cast)
    /// (N, E, 23) entity features.
    pub entity_features: Tensor<B, 3>,
    /// (N, E) entity type IDs.
    pub entity_types: Tensor<B, 2, Int>,
    /// (N, E) entity mask (True = padding).
    pub entity_mask: Tensor<B, 2, Bool>,
    /// (N, T, 8) threat features.
    pub threat_features: Tensor<B, 3>,
    /// (N, T) threat mask.
    pub threat_mask: Tensor<B, 2, Bool>,
    /// (N, P, 8) position features.
    pub position_features: Tensor<B, 3>,
    /// (N, P) position mask.
    pub position_mask: Tensor<B, 2, Bool>,
    /// (N, A, 34) ability slot features.
    pub ability_features: Tensor<B, 3>,
    /// (N, A) ability slot type IDs.
    pub ability_types: Tensor<B, 2, Int>,
    /// (N, A) ability slot mask.
    pub ability_mask: Tensor<B, 2, Bool>,

    // Operator inputs
    /// (N, 32) frozen ability CLS embedding for the cast ability.
    pub ability_cls: Tensor<B, 2>,
    /// (N,) caster entity slot index.
    pub caster_slot: Tensor<B, 1, Int>,
    /// (N,) duration_norm = window_ms / MAX_WINDOW_MS.
    pub duration_norm: Tensor<B, 1>,

    // Targets (state after ability resolves)
    /// (N, E, 3) delta hp_pct, shield_pct, resource_pct.
    pub target_hp: Tensor<B, 3>,
    /// (N, E, 1) cc_remaining after.
    pub target_cc: Tensor<B, 3>,
    /// (N, E, 1) is_stunned after.
    pub target_cc_stun: Tensor<B, 3>,
    /// (N, E, 2) delta_x, delta_y.
    pub target_pos: Tensor<B, 3>,
    /// (N, E, 1) exists after.
    pub target_exists: Tensor<B, 3>,

    // Metadata
    /// Per-sample loss masks.
    pub loss_masks: Vec<LossMask>,
    /// Per-sample scenario index (for train/val split).
    pub scenario_ids: Vec<u32>,
    /// Total number of samples.
    pub n_samples: usize,
}

impl<B: Backend> OperatorDataset<B> {
    /// Load dataset from npz file.
    ///
    /// Expected arrays in the npz:
    /// - `entity_features`: (N, E*23)
    /// - `entity_types`: (N, E) — i32
    /// - `entity_mask`: (N, E) — i32 (1=pad)
    /// - `threat_features`: (N, T*8)
    /// - `threat_mask`: (N, T) — i32
    /// - `position_features`: (N, P*8)
    /// - `position_mask`: (N, P) — i32
    /// - `ability_slot_features`: (N, A*34)
    /// - `ability_slot_types`: (N, A) — i32
    /// - `ability_slot_mask`: (N, A) — i32
    /// - `ability_cls`: (N, 32)
    /// - `caster_slot`: (N,) — i32
    /// - `duration_norm`: (N,)
    /// - `target_hp`: (N, E*3)
    /// - `target_cc`: (N, E*1)
    /// - `target_cc_stun`: (N, E*1)
    /// - `target_pos`: (N, E*2)
    /// - `target_exists`: (N, E*1)
    /// - `ability_props`: (N, 80)
    /// - `scenario_ids`: (N,) — i32
    pub fn load(path: &Path, device: &B::Device) -> Self {
        let file = std::fs::File::open(path)
            .unwrap_or_else(|e| panic!("Failed to open {}: {e}", path.display()));
        let mut npz = NpzReader::new(file)
            .unwrap_or_else(|e| panic!("Failed to read npz {}: {e}", path.display()));

        let n_ent = MAX_ENTITIES;
        let n_thr = MAX_THREATS;
        let n_pos = MAX_POSITIONS;

        // Helper to load f32 array and convert to tensor
        let load_f32 = |npz: &mut NpzReader<std::fs::File>, name: &str| -> Array2<f32> {
            npz.by_name(name)
                .unwrap_or_else(|e| panic!("Missing array '{name}' in npz: {e}"))
        };
        let load_i32 = |npz: &mut NpzReader<std::fs::File>, name: &str| -> Array2<i32> {
            npz.by_name(name)
                .unwrap_or_else(|e| panic!("Missing array '{name}' in npz: {e}"))
        };

        // Load arrays
        let ent_feat_arr = load_f32(&mut npz, "entity_features");
        let n_samples = ent_feat_arr.shape()[0];

        let ent_types_arr = load_i32(&mut npz, "entity_types");
        let ent_mask_arr = load_i32(&mut npz, "entity_mask");
        let thr_feat_arr = load_f32(&mut npz, "threat_features");
        let thr_mask_arr = load_i32(&mut npz, "threat_mask");
        let pos_feat_arr = load_f32(&mut npz, "position_features");
        let pos_mask_arr = load_i32(&mut npz, "position_mask");
        let abl_feat_arr = load_f32(&mut npz, "ability_slot_features");
        let abl_types_arr = load_i32(&mut npz, "ability_slot_types");
        let abl_mask_arr = load_i32(&mut npz, "ability_slot_mask");
        let cls_arr = load_f32(&mut npz, "ability_cls");
        let caster_arr = load_i32(&mut npz, "caster_slot");
        let dur_arr = load_f32(&mut npz, "duration_norm");
        let target_hp_arr = load_f32(&mut npz, "target_hp");
        let target_cc_arr = load_f32(&mut npz, "target_cc");
        let target_stun_arr = load_f32(&mut npz, "target_cc_stun");
        let target_pos_arr = load_f32(&mut npz, "target_pos");
        let target_exists_arr = load_f32(&mut npz, "target_exists");
        let props_arr = load_f32(&mut npz, "ability_props");
        let scenario_ids_arr = load_i32(&mut npz, "scenario_ids");

        // Determine ability slot count from data
        let n_abl = abl_feat_arr.shape()[1] / ABILITY_SLOT_DIM;

        // Convert to tensors
        let to_tensor_3d = |arr: Array2<f32>, rows: usize, dim: usize| -> Tensor<B, 3> {
            let flat: Vec<f32> = arr.into_raw_vec();
            Tensor::<B, 1>::from_data(TensorData::from(flat.as_slice()), device)
                .reshape([n_samples, rows, dim])
        };
        let to_int_2d = |arr: Array2<i32>, cols: usize| -> Tensor<B, 2, Int> {
            let flat: Vec<i32> = arr.into_raw_vec();
            Tensor::<B, 1, Int>::from_data(TensorData::from(flat.as_slice()), device)
                .reshape([n_samples, cols])
        };
        let to_bool_2d = |arr: Array2<i32>, cols: usize| -> Tensor<B, 2, Bool> {
            let flat: Vec<i32> = arr.into_raw_vec();
            let t = Tensor::<B, 1, Int>::from_data(TensorData::from(flat.as_slice()), device)
                .reshape([n_samples, cols]);
            t.greater_elem(0) // 1 → True (padding)
        };

        // Build loss masks from ability properties
        let loss_masks: Vec<LossMask> = (0..n_samples)
            .map(|i| {
                let mut props = [0.0f32; 80];
                for j in 0..80 {
                    props[j] = props_arr[[i, j]];
                }
                LossMask::from_props(&props)
            })
            .collect();

        let scenario_ids: Vec<u32> = (0..n_samples)
            .map(|i| scenario_ids_arr[[i, 0]] as u32)
            .collect();

        OperatorDataset {
            entity_features: to_tensor_3d(ent_feat_arr, n_ent, ENTITY_DIM),
            entity_types: to_int_2d(ent_types_arr, n_ent),
            entity_mask: to_bool_2d(ent_mask_arr, n_ent),
            threat_features: to_tensor_3d(thr_feat_arr, n_thr, THREAT_DIM),
            threat_mask: to_bool_2d(thr_mask_arr, n_thr),
            position_features: to_tensor_3d(pos_feat_arr, n_pos, POSITION_DIM),
            position_mask: to_bool_2d(pos_mask_arr, n_pos),
            ability_features: to_tensor_3d(abl_feat_arr, n_abl, ABILITY_SLOT_DIM),
            ability_types: to_int_2d(abl_types_arr, n_abl),
            ability_mask: to_bool_2d(abl_mask_arr, n_abl),
            ability_cls: {
                let flat: Vec<f32> = cls_arr.into_raw_vec();
                Tensor::<B, 1>::from_data(TensorData::from(flat.as_slice()), device)
                    .reshape([n_samples, ABILITY_CLS_DIM])
            },
            caster_slot: {
                let flat: Vec<i32> = caster_arr.into_raw_vec();
                Tensor::<B, 1, Int>::from_data(TensorData::from(flat.as_slice()), device)
                    .reshape([n_samples])
            },
            duration_norm: {
                let flat: Vec<f32> = dur_arr.into_raw_vec();
                Tensor::<B, 1>::from_data(TensorData::from(flat.as_slice()), device)
                    .reshape([n_samples])
            },
            target_hp: to_tensor_3d(target_hp_arr, n_ent, 3),
            target_cc: to_tensor_3d(target_cc_arr, n_ent, 1),
            target_cc_stun: to_tensor_3d(target_stun_arr, n_ent, 1),
            target_pos: to_tensor_3d(target_pos_arr, n_ent, 2),
            target_exists: to_tensor_3d(target_exists_arr, n_ent, 1),
            loss_masks,
            scenario_ids,
            n_samples,
        }
    }

    /// Convert dataset from autodiff backend to inner backend for evaluation.
    pub fn to_inner(&self) -> OperatorDataset<B::InnerBackend>
    where
        B: burn::tensor::backend::AutodiffBackend,
    {
        // Bool tensors don't track gradients, so we reconstruct them
        // from int tensors on the inner backend.
        let device = self.entity_features.device();
        let bool_inner = |t: &Tensor<B, 2, Bool>| -> Tensor<B::InnerBackend, 2, Bool> {
            let int_t: Tensor<B, 2, Int> = t.clone().int();
            let inner_int = int_t.inner();
            inner_int.greater_elem(0)
        };

        OperatorDataset {
            entity_features: self.entity_features.clone().inner(),
            entity_types: self.entity_types.clone().inner(),
            entity_mask: bool_inner(&self.entity_mask),
            threat_features: self.threat_features.clone().inner(),
            threat_mask: bool_inner(&self.threat_mask),
            position_features: self.position_features.clone().inner(),
            position_mask: bool_inner(&self.position_mask),
            ability_features: self.ability_features.clone().inner(),
            ability_types: self.ability_types.clone().inner(),
            ability_mask: bool_inner(&self.ability_mask),
            ability_cls: self.ability_cls.clone().inner(),
            caster_slot: self.caster_slot.clone().inner(),
            duration_norm: self.duration_norm.clone().inner(),
            target_hp: self.target_hp.clone().inner(),
            target_cc: self.target_cc.clone().inner(),
            target_cc_stun: self.target_cc_stun.clone().inner(),
            target_pos: self.target_pos.clone().inner(),
            target_exists: self.target_exists.clone().inner(),
            loss_masks: self.loss_masks.clone(),
            scenario_ids: self.scenario_ids.clone(),
            n_samples: self.n_samples,
        }
    }

    /// Split into train/val by scenario ID.
    ///
    /// Returns (train_indices, val_indices) where val scenarios are
    /// the last 20% of unique scenario IDs.
    pub fn train_val_split(&self) -> (Vec<usize>, Vec<usize>) {
        let mut unique_scenarios: Vec<u32> = self.scenario_ids.iter().copied().collect();
        unique_scenarios.sort_unstable();
        unique_scenarios.dedup();

        let n_val = (unique_scenarios.len() as f32 * 0.2).ceil() as usize;
        let val_start = unique_scenarios.len() - n_val;
        let val_scenarios: std::collections::HashSet<u32> =
            unique_scenarios[val_start..].iter().copied().collect();

        let mut train = Vec::new();
        let mut val = Vec::new();

        for (i, &sid) in self.scenario_ids.iter().enumerate() {
            if val_scenarios.contains(&sid) {
                val.push(i);
            } else {
                train.push(i);
            }
        }

        (train, val)
    }
}
